        if (auto *CV = dyn_cast<ConstantVector>(C)) {
          for (Value *Elt : CV->operands()) {
            auto *CI = dyn_cast<ConstantInt>(Elt);
            if (!CI || CI->isZero() || CI->isOne())
              return true;
          }
          return false;
